import json
with open('baseline-packages.json') as f: base = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        pkgs = {}
        for fw in proj.get('frameworks', []):
            for p in fw.get('topLevelPackages', []):
                pkgs[p['id']] = p.get('resolvedVersion', p.get('requestedVersion','?'))
        result[name] = pkgs
    return result

bp = get_pkgs(base)
ap = get_pkgs(after)

print('=== Changes ===')
changed = False
for proj in sorted(set(list(bp.keys()) + list(ap.keys()))):
    for pkg in sorted(set(list(bp.get(proj,{}).keys()) + list(ap.get(proj,{}).keys()))):
        bv = bp.get(proj,{}).get(pkg)
        av = ap.get(proj,{}).get(pkg)
        if bv != av:
            changed = True
            print(f'  {proj}: {pkg} {bv} -> {av}')
if not changed:
    print('  (none besides intended alignments)')

print()
print('=== All resolved versions (after) ===')
for proj in sorted(ap):
    for pkg in sorted(ap[proj]):
        print(f'  {proj}: {pkg} = {ap[proj][pkg]}')
"

